import copy
import json

from ledger import project

with open(\"events.json\", encoding=\"utf-8\") as handle:
    events = json.load(handle)
original = copy.deepcopy(events)
assert project(events) == {
    \"accounts\": [
        {\"account\": \"a1\", \"last_seq\": 3, \"active\": [\"export\"]},
        {\"account\": \"a2\", \"last_seq\": 3, \"active\": [\"audit\"]},
        {\"account\": \"a3\", \"last_seq\": 2, \"active\": [\"gamma\"]},
    ],
    \"events_applied\": 8,
}
assert events == original

same_id_different_key_order = [
    {\"event_id\": \"x\", \"account\": \"b\", \"seq\": 1, \"op\": \"grant\", \"entitlement\": \"z\"},
    {\"entitlement\": \"z\", \"op\": \"grant\", \"seq\": 1, \"account\": \"b\", \"event_id\": \"x\"},
]
assert project(same_id_different_key_order)[\"events_applied\"] == 1

try:
    project([
        {\"event_id\": \"x\", \"account\": \"b\", \"seq\": 1, \"op\": \"grant\", \"entitlement\": \"z\"},
        {\"event_id\": \"x\", \"account\": \"b\", \"seq\": 1, \"op\": \"revoke\", \"entitlement\": \"z\"},
    ])
except ValueError:
    pass
else:
    raise AssertionError(\"reused event_id did not fail\")

try:
    project([
        {\"event_id\": \"x\", \"account\": \"b\", \"seq\": 2, \"op\": \"grant\", \"entitlement\": \"z\"},
    ])
except ValueError:
    pass
else:
    raise AssertionError(\"non-contiguous sequence did not fail\")

print(\"focused ledger checks passed\")
